        public static void Validate(ISequenceProvider sequenceProvider, IChromosome chromosome, string transcriptId,
            bool onReverseStrand, ITranscriptRegion[] transcriptRegions, IRnaEdit[] rnaEdits, ITranslation translation,
            byte startExonPhase = 0)
        {
            sequenceProvider.LoadChromosome(chromosome);

            if (TranscriptCdnas.TryGetValue(transcriptId, out var expectedCdna))
            {
                var cdnaSequence = new CdnaSequence(sequenceProvider.Sequence, translation?.CodingRegion,
                    transcriptRegions, onReverseStrand, rnaEdits);
                string cdna = cdnaSequence.GetCdnaSequence();
                if (cdna != expectedCdna) throw new InvalidDataException($"{transcriptId} cdna is still not right.");
            }
            else
            {
                throw new InvalidDataException($"{transcriptId} cdna not listed");
            }
            
            string cds = null;
            if (TranscriptCds.TryGetValue(transcriptId, out var expectedCds))
            {
                var cdsSequence = new CodingSequence(sequenceProvider.Sequence, translation.CodingRegion,
                    transcriptRegions, onReverseStrand, startExonPhase, rnaEdits);
                cds = cdsSequence.GetCodingSequence();

                if (cds != expectedCds) throw new InvalidDataException($"{transcriptId} CDS is still not right.");
            }

            if (cds != null && TranscriptPeptides.TryGetValue(transcriptId, out var expectedAA))
            {
                var    aminoAcids = new AminoAcids(false);
                string aa         = aminoAcids.TranslateBases(cds, false);

                if (aa != expectedAA) throw new InvalidDataException($"{transcriptId} AA is still not right.");
            }
        }

        public static void CheckTranscriptRegions(string transcriptId, ITranscriptRegion[] transcriptRegions)
        {
            CheckGenomicAndCdnaLength(transcriptId, transcriptRegions);
            ValidateRegions(transcriptId, transcriptRegions);
            if (transcriptRegions.Length <= 1) return;
            CheckGenomicCoordinateContiguity(transcriptId, transcriptRegions);
        }

        private static void CheckGenomicAndCdnaLength(string transcriptId, ITranscriptRegion[] transcriptRegions)
        {
            foreach (var region in transcriptRegions)
            {
                if (region.Type != TranscriptRegionType.Exon) continue;
                int deltaGenome = region.End     - region.Start     + 1;
                int deltaCdna   = region.CdnaEnd - region.CdnaStart + 1;
                if (deltaCdna != deltaGenome)
                    throw new InvalidDataException(
                        $"Found an invalid exon in {transcriptId}: {region.Id}, genomic: [{region.Start}, {region.End}], cDNA: [{region.CdnaStart}, {region.CdnaEnd}], delta genome: {deltaGenome}, delta cDNA: {deltaCdna}");
            }
        }

        private static void CheckGenomicCoordinateContiguity(string transcriptId, IReadOnlyList<ITranscriptRegion> regions)
        {
            for (var i = 1; i < regions.Count; i++)
            {
                var prevRegion = regions[i - 1];
                var region     = regions[i];

                int delta = region.Start - prevRegion.End;
                if (delta != 1) throw new InvalidDataException($"Found non-contiguous genomic coordinates in transcript regions in transcript ({transcriptId}).");
            }
        }

        private static void ValidateRegions(string transcriptId, IEnumerable<ITranscriptRegion> regions)
        {
            foreach (var region in regions)
            {
                if (region.Id == 0)       throw new InvalidDataException($"Expected transcript ({transcriptId}) to have regions with non-zero IDs.");
                if (region.CdnaStart < 1) throw new InvalidDataException($"Expected transcript ({transcriptId}) to have regions with true cDNA start positions.");
                if (region.CdnaEnd < 1)   throw new InvalidDataException($"Expected transcript ({transcriptId}) to have regions with true cDNA end positions.");

                if (region.Type != TranscriptRegionType.Exon && region.Type != TranscriptRegionType.Intron &&
                    region.Type != TranscriptRegionType.Gap)
                    throw new InvalidDataException($"Found unexpected transcript region type ({region.Type}) in transcript ({transcriptId}).");
            }
        }

        public static void DumpExon(ISequence sequence, string transcriptCdnaBases, TranscriptRegion exon, bool onReverseStrand)
        {
            int genomicLength = exon.End     - exon.Start     + 1;
            int cdnaLength    = exon.CdnaEnd - exon.CdnaStart + 1;
            
            var genomicBases   = sequence.Substring(exon.Start - 1, genomicLength);
            if(onReverseStrand) genomicBases = SequenceUtilities.GetReverseComplement(genomicBases);
            
            string cdnaBases = transcriptCdnaBases.Substring(exon.CdnaStart-1, cdnaLength);
            
            Console.WriteLine($"{exon.Start,10:N0} {genomicBases} {exon.End:N0} [{genomicLength}]");
            Console.WriteLine($"{exon.CdnaStart,10:N0} {cdnaBases} {exon.CdnaEnd:N0} [{cdnaLength}]");
            Console.WriteLine(cdnaBases == genomicBases ? "SAME\n" : "DIFFERENT\n");
        }

        public static void DumpCodingRegion(ISequence sequence, string transcriptCdnaBases, string transcriptCdsBases,
            CodingRegion codingRegion, bool onReverseStrand)
        {
            const int compareLength = 20;
            int       genomicLength = codingRegion.End     - codingRegion.Start     + 1;
            int       cdnaLength    = codingRegion.CdnaEnd - codingRegion.CdnaStart + 1;

            string genomicBases               = sequence.Substring(codingRegion.Start - 1, genomicLength);
            if (onReverseStrand) genomicBases = SequenceUtilities.GetReverseComplement(genomicBases);

            string cdnaBases = transcriptCdnaBases.Substring(codingRegion.CdnaStart - 1, cdnaLength);

            // check the 5' end
            string transcriptCdsBases5Prime = transcriptCdsBases.Substring(0, compareLength);
            string genomicBases5Prime       = genomicBases.Substring(0, compareLength);
            string cdnaBases5Prime          = cdnaBases.Substring(0, compareLength);

            Console.WriteLine($"CDS 5':    {transcriptCdsBases5Prime}");
            Console.WriteLine($"{codingRegion.Start,10:N0} {genomicBases5Prime} {codingRegion.End:N0}");
            Console.WriteLine($"{codingRegion.CdnaStart,10:N0} {cdnaBases5Prime} {codingRegion.CdnaEnd:N0}");
            bool allAgree = transcriptCdsBases5Prime == genomicBases5Prime &&
                            transcriptCdsBases5Prime == cdnaBases5Prime;
            Console.WriteLine(allAgree ? "SAME\n" : "DIFFERENT\n");
            
            // check the 3' end
            string transcriptCdsBases3Prime = transcriptCdsBases.Substring(transcriptCdsBases.Length - compareLength);
            string genomicBases3Prime       = genomicBases.Substring(genomicBases.Length             - compareLength);
            string cdnaBases3Prime          = cdnaBases.Substring(cdnaBases.Length                   - compareLength);

            Console.WriteLine($"CDS 3':    {transcriptCdsBases3Prime}");
            Console.WriteLine($"{codingRegion.Start,10:N0} {genomicBases3Prime} {codingRegion.End:N0}");
            Console.WriteLine($"{codingRegion.CdnaStart,10:N0} {cdnaBases3Prime} {codingRegion.CdnaEnd:N0}");
            allAgree = transcriptCdsBases3Prime == genomicBases3Prime &&
                            transcriptCdsBases3Prime == cdnaBases3Prime;
            Console.WriteLine(allAgree ? "SAME\n" : "DIFFERENT\n");
            
            // check the two CDS interpretations
            Console.Write("Checking trimmed cDNA against truth CDS: ");
            Console.WriteLine(cdnaBases == transcriptCdsBases ? "SAME\n" : "DIFFERENT\n");
        }
    }
